<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      color-scheme: light;
      font-family: Arial, Helvetica, sans-serif;
      background: #f4f6f8;
      color: #1f2933;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 24px;
    }

    .app {
      width: min(900px, 100%);
      margin: 0 auto;
    }

    h1,
    h2 {
      margin-top: 0;
    }

    .panel {
      margin-bottom: 20px;
      padding: 20px;
      border: 1px solid #d9e0e7;
      border-radius: 10px;
      background: #fff;
      box-shadow: 0 2px 8px rgba(31, 41, 51, 0.06);
    }

    .form-grid,
    .filter-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 14px;
    }

    label {
      display: flex;
      flex-direction: column;
      gap: 6px;
      font-weight: 600;
    }

    input,
    select,
    button {
      min-height: 42px;
      border: 1px solid #b8c2cc;
      border-radius: 6px;
      font: inherit;
    }

    input,
    select {
      width: 100%;
      padding: 8px 10px;
      background: #fff;
      color: #1f2933;
    }

    input:focus,
    select:focus,
    button:focus {
      outline: 3px solid rgba(37, 99, 235, 0.2);
      border-color: #2563eb;
    }

    button {
      padding: 9px 16px;
      cursor: pointer;
      font-weight: 700;
    }

    #add-expense {
      margin-top: 16px;
      border-color: #2563eb;
      background: #2563eb;
      color: #fff;
    }

    #add-expense:hover {
      background: #1d4ed8;
    }

    #form-error {
      min-height: 1.25em;
      margin: 10px 0 0;
      color: #b42318;
      font-weight: 600;
    }

    .summary {
      display: grid;
      grid-template-columns: 1.3fr repeat(4, 1fr);
      gap: 10px;
      margin-bottom: 20px;
    }

    .summary-item {
      padding: 14px;
      border: 1px solid #d9e0e7;
      border-radius: 8px;
      background: #fff;
    }

    .summary-item strong,
    .summary-item span {
      display: block;
    }

    .summary-item span {
      margin-top: 5px;
      font-size: 1.15rem;
      font-weight: 700;
    }

    .expense-list {
      display: grid;
      gap: 10px;
    }

    .expense {
      display: grid;
      grid-template-columns: minmax(100px, 0.8fr) minmax(110px, 1fr) minmax(120px, 1fr) minmax(100px, 1.5fr) auto;
      gap: 12px;
      align-items: center;
      padding: 14px;
      border: 1px solid #d9e0e7;
      border-radius: 8px;
      background: #fff;
    }

    .expense[hidden] {
      display: none;
    }

    .expense-amount {
      font-size: 1.08rem;
      font-weight: 700;
    }

    .expense-category {
      text-transform: capitalize;
    }

    .expense-note {
      overflow-wrap: anywhere;
      color: #52606d;
    }

    .exp-del {
      min-height: 36px;
      border-color: #d92d20;
      background: #fff;
      color: #b42318;
    }

    .exp-del:hover {
      background: #fff1f0;
    }

    #empty-message {
      margin: 0;
      padding: 22px;
      border: 1px dashed #b8c2cc;
      border-radius: 8px;
      text-align: center;
      color: #52606d;
      background: #fff;
    }

    @media (max-width: 760px) {
      .summary {
        grid-template-columns: repeat(2, minmax(0, 1fr));
      }

      .expense {
        grid-template-columns: 1fr 1fr;
      }

      .expense-note {
        grid-column: 1 / -1;
      }

      .exp-del {
        justify-self: start;
      }
    }

    @media (max-width: 520px) {
      body {
        padding: 12px;
      }

      .form-grid,
      .filter-grid,
      .summary {
        grid-template-columns: 1fr;
      }

      .expense {
        grid-template-columns: 1fr;
      }

      .expense-note {
        grid-column: auto;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <h1>Personal Expense Tracker</h1>

    <section class="panel" aria-labelledby="entry-title">
      <h2 id="entry-title">Add an expense</h2>
      <form id="expense-form" novalidate>
        <div class="form-grid">
          <label for="amount">
            Amount
            <input id="amount" name="amount" type="number" min="0.01" step="0.01" inputmode="decimal" placeholder="0.00">
          </label>

          <label for="category">
            Category
            <select id="category" name="category">
              <option value="groceries">Groceries</option>
              <option value="transport">Transport</option>
              <option value="bills">Bills</option>
              <option value="fun">Fun</option>
            </select>
          </label>

          <label for="date">
            Date
            <input id="date" name="date" type="date">
          </label>

          <label for="note">
            Note (optional)
            <input id="note" name="note" type="text" maxlength="160" placeholder="What was this for?">
          </label>
        </div>

        <button id="add-expense" type="submit">Add expense</button>
        <p id="form-error" role="alert" aria-live="polite"></p>
      </form>
    </section>

    <section class="panel" aria-labelledby="filter-title">
      <h2 id="filter-title">Filters</h2>
      <div class="filter-grid">
        <label for="filter-category">
          Category
          <select id="filter-category">
            <option value="all">All categories</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </label>

        <label for="filter-from">
          From
          <input id="filter-from" type="date">
        </label>

        <label for="filter-to">
          To
          <input id="filter-to" type="date">
        </label>
      </div>
    </section>

    <section class="summary" aria-label="Visible expense summary">
      <div class="summary-item">
        <strong>Visible total</strong>
        <span id="total">0.00</span>
      </div>
      <div class="summary-item cat-total" data-cat="groceries">
        <strong>Groceries</strong>
        <span>Groceries: 0.00</span>
      </div>
      <div class="summary-item cat-total" data-cat="transport">
        <strong>Transport</strong>
        <span>Transport: 0.00</span>
      </div>
      <div class="summary-item cat-total" data-cat="bills">
        <strong>Bills</strong>
        <span>Bills: 0.00</span>
      </div>
      <div class="summary-item cat-total" data-cat="fun">
        <strong>Fun</strong>
        <span>Fun: 0.00</span>
      </div>
    </section>

    <section aria-labelledby="expenses-title">
      <h2 id="expenses-title">Expenses</h2>
      <div id="expense-list" class="expense-list"></div>
      <p id="empty-message">No expenses yet.</p>
    </section>
  </main>

  <script>
    (function () {
      "use strict";

      const STORAGE_KEY = "personal-expense-tracker-expenses";
      const categories = ["groceries", "transport", "bills", "fun"];

      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const formError = document.getElementById("form-error");

      const categoryFilter = document.getElementById("filter-category");
      const fromFilter = document.getElementById("filter-from");
      const toFilter = document.getElementById("filter-to");

      const expenseList = document.getElementById("expense-list");
      const emptyMessage = document.getElementById("empty-message");
      const totalElement = document.getElementById("total");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (!Array.isArray(saved)) return [];

          return saved.filter(function (expense) {
            return expense &&
              Number.isFinite(Number(expense.amount)) &&
              Number(expense.amount) > 0 &&
              categories.includes(expense.category) &&
              typeof expense.date === "string" &&
              expense.date.length > 0;
          }).map(function (expense, index) {
            return {
              id: String(expense.id || (Date.now() + "-" + index)),
              amount: Number(expense.amount),
              category: expense.category,
              date: expense.date,
              note: typeof expense.note === "string" ? expense.note : ""
            };
          });
        } catch (error) {
          return [];
        }
      }

      function saveExpenses() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        } catch (error) {
          // The tracker remains usable for the current session if storage fails.
        }
      }

      function makeId() {
        return Date.now().toString(36) + "-" + Math.random().toString(36).slice(2);
      }

      function formatCategory(category) {
        return category.charAt(0).toUpperCase() + category.slice(1);
      }

      function createExpenseRow(expense) {
        const row = document.createElement("article");
        row.className = "expense";
        row.dataset.id = expense.id;
        row.dataset.category = expense.category;
        row.dataset.date = expense.date;
        row.dataset.amount = String(expense.amount);

        const amount = document.createElement("div");
        amount.className = "expense-amount";
        amount.textContent = "$" + expense.amount.toFixed(2);

        const category = document.createElement("div");
        category.className = "expense-category";
        category.textContent = formatCategory(expense.category);

        const date = document.createElement("time");
        date.className = "expense-date";
        date.dateTime = expense.date;
        date.textContent = expense.date;

        const note = document.createElement("div");
        note.className = "expense-note";
        note.textContent = expense.note || "No note";

        const deleteButton = document.createElement("button");
        deleteButton.type = "button";
        deleteButton.className = "exp-del";
        deleteButton.textContent = "Delete";
        deleteButton.setAttribute("aria-label", "Delete " + expense.category + " expense");

        deleteButton.addEventListener("click", function () {
          expenses = expenses.filter(function (item) {
            return item.id !== expense.id;
          });
          saveExpenses();
          render();
        });

        row.append(amount, category, date, note, deleteButton);
        return row;
      }

      function isVisible(expense) {
        const selectedCategory = categoryFilter.value;
        const from = fromFilter.value;
        const to = toFilter.value;

        const categoryMatches =
          selectedCategory === "all" || expense.category === selectedCategory;
        const fromMatches = !from || expense.date >= from;
        const toMatches = !to || expense.date <= to;

        return categoryMatches && fromMatches && toMatches;
      }

      function updateSummary(visibleExpenses) {
        const categoryTotals = {
          groceries: 0,
          transport: 0,
          bills: 0,
          fun: 0
        };

        let total = 0;

        visibleExpenses.forEach(function (expense) {
          total += expense.amount;
          categoryTotals[expense.category] += expense.amount;
        });

        totalElement.textContent = total.toFixed(2);

        document.querySelectorAll(".cat-total").forEach(function (element) {
          const category = element.dataset.cat;
          const valueElement = element.querySelector("span");
          valueElement.textContent =
            formatCategory(category) + ": " + categoryTotals[category].toFixed(2);
        });
      }

      function render() {
        expenseList.textContent = "";
        const visibleExpenses = [];

        expenses.forEach(function (expense) {
          const row = createExpenseRow(expense);
          const visible = isVisible(expense);
          row.hidden = !visible;

          if (visible) {
            visibleExpenses.push(expense);
          }

          expenseList.appendChild(row);
        });

        if (expenses.length === 0) {
          emptyMessage.textContent = "No expenses yet.";
          emptyMessage.hidden = false;
        } else if (visibleExpenses.length === 0) {
          emptyMessage.textContent = "No expenses match the current filters.";
          emptyMessage.hidden = false;
        } else {
          emptyMessage.hidden = true;
        }

        updateSummary(visibleExpenses);
      }

      form.addEventListener("submit", function (event) {
        event.preventDefault();

        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const date = dateInput.value;

        if (rawAmount === "" || !Number.isFinite(amount) || amount <= 0) {
          formError.textContent = "Enter an amount greater than zero.";
          amountInput.focus();
          return;
        }

        if (!date) {
          formError.textContent = "Select a date.";
          dateInput.focus();
          return;
        }

        expenses.unshift({
          id: makeId(),
          amount: amount,
          category: categoryInput.value,
          date: date,
          note: noteInput.value.trim()
        });

        saveExpenses();
        formError.textContent = "";
        amountInput.value = "";
        noteInput.value = "";
        render();
        amountInput.focus();
      });

      [categoryFilter, fromFilter, toFilter].forEach(function (control) {
        control.addEventListener("change", render);
        control.addEventListener("input", render);
      });

      render();
    })();
  </script>
</body>
</html>
